import React, { useState } from "react";
import axios from "axios";

export default function Register() {
  const [form, setForm] = useState({ name: "", email: "", password: "" });
  const [msg, setMsg] = useState("");

  const handleChange = (e) => {
    setForm({ ...form, [e.target.name]: e.target.value });
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    try {
      await axios.post("http://localhost:5000/api/auth/register", form);
      setMsg("Registration Successful");
    } catch (err) {
      setMsg("Error: " + err.response.data.error);
    }
  };

  return (
    <div className="container my-5">
      <h2>Register</h2>
      <form onSubmit={handleSubmit}>
        <input name="name" placeholder="Name" className="form-control mb-2" onChange={handleChange}/>
        <input name="email" placeholder="Email" className="form-control mb-2" onChange={handleChange}/>
        <input name="password" placeholder="Password" type="password" className="form-control mb-2" onChange={handleChange}/>
        <button className="btn btn-primary w-100">Register</button>
      </form>
      <p>{msg}</p>
    </div>
  );
}
